            sink.emit(&LoopAuditEvent::IterationBoundary {
                ts: Utc::now(),
                run_id: cfg.run_id.clone(),
                session_id: session.id().to_string(),
                iteration,
                continues,
            });
            trace.push(IterationTrace {
